'use strict';

exports.handler = (event) => {
    const response = event.Records[0].cf.response;
    const contentType = response.headers['content-type'][0].value;

    if (contentType === 'text/html') {
        const injectionPoints = event.Records[0].cf.request.headers['x-injection-points'] || [];
        const userContent = event.Records[0].cf.request.headers['x-user-content'] || [];

        if (injectionPoints.length > 0 && userContent.length > 0) {
            let bodyBuffer = Buffer.from(response.body.data, 'base64');
            let responseBody = bodyBuffer.toString('utf-8');

            injectionPoints.forEach((point, index) => {
                const pointValue = point.value;
                const contentValue = userContent[index].value;
                responseBody = responseBody.replace(pointValue, pointValue + contentValue);
            });

            response.body = Buffer.from(responseBody).toString('base64');
            response.headers['content-length'][0].value = response.body.length.toString();
        }
    }

    return response;
};